		description:null,
		image_1:null,
		image_2:null,
		image_3:null,
		image_4:null,
		image_5:null,
		image_6:null,
		user_id:localStorage.getItem('userId')
	})

	useEffect(() => {
		getDesigner(setDesigners)
		getSize(setSizes)
		getCondition(setConditions)
		getCategory(setCategories)
		getSubCategory(setSubCategories)

		const categoryMap = getMap(dropdownRef)

		const release = (e) => {
			if (CategoryRef.current !== null &&
				SubCategoryRef.current !== null &&
				designerRef.current !== null &&
				sizeRef.current !== null &&
				conditionRef.current !== null) {
				if (!CategoryRef.current.contains(e.target) &&
				!SubCategoryRef.current.contains(e.target) &&
				!designerRef.current.contains(e.target) &&
				!sizeRef.current.contains(e.target) &&
				!conditionRef.current.contains(e.target)) {
					setDropdownActive(false)
					for (let categoryNode of categoryMap) {
						categoryNode[1].style.display = 'none'
					}
				}
			}
		}

		document.addEventListener('mousedown', release)
	},[])


	const getMap = (ref) => {
		if (!ref.current) {
			ref.current = new Map()
		}
		return ref.current
	}

	const getNode = (node, key, ref) => {
		const map = getMap(ref)
		if (node) {
			map.set(key, node)
		}
	}

	const onDropdown = (key) => {
		const categoryMap = getMap(dropdownRef)
		const categoryNode = categoryMap.get(key)
		if (categoryNode.style.display === '' || categoryNode.style.display === 'none') {
			categoryNode.style.display = 'block'
		} else {
